import{_ as o,c as a,o as r,a1 as s}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Termos de Uso: Regras de Serviço | OpenCodeDocs","description":"Entenda as regras de uso do serviço, direitos de propriedade intelectual e cláusulas de isenção de responsabilidade dos Termos de Uso do OpenCodeDocs, esclarecendo os direitos e obrigações de ambas as partes.","frontmatter":{"title":"Termos de Uso: Regras de Serviço | OpenCodeDocs","sidebarTitle":"Entenda as Regras em 5 Minutos","subtitle":"Termos de Uso: Regras de Serviço","description":"Entenda as regras de uso do serviço, direitos de propriedade intelectual e cláusulas de isenção de responsabilidade dos Termos de Uso do OpenCodeDocs, esclarecendo os direitos e obrigações de ambas as partes."},"headers":[],"relativePath":"pt/terms.md","filePath":"pt/terms.md"}'),i={name:"pt/terms.md"};function t(d,e,n,c,l,u){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="termos-de-servico-ao-usuario" tabindex="-1">Termos de Serviço ao Usuário <a class="header-anchor" href="#termos-de-servico-ao-usuario" aria-label="Permalink to &quot;Termos de Serviço ao Usuário&quot;">​</a></h1><p>Última atualização: 2026-01-01 Data de entrada em vigor: 2026-01-01</p><p>Bem-vindo ao OpenCodeDocs! Antes de usar nossos serviços, leia atentamente estes Termos de Serviço ao Usuário (doravante &quot;este Acordo&quot;). Ao usar nossos serviços, você concorda em ficar vinculado a este Acordo.</p><h2 id="_1-descricao-do-servico" tabindex="-1">1. Descrição do Serviço <a class="header-anchor" href="#_1-descricao-do-servico" aria-label="Permalink to &quot;1. Descrição do Serviço&quot;">​</a></h2><p>OpenCodeDocs é uma plataforma aberta focada em tutoriais de ferramentas de IA, oferecendo os seguintes serviços:</p><ul><li><strong>Conteúdo do Tutorial</strong>: Tutoriais de uso para ferramentas de IA de código aberto (como Claude Code, Cursor, LangChain, etc.)</li><li><strong>Verificação de Código</strong>: Verifica automaticamente a executabilidade do código nos tutoriais com base no repositório de código fonte</li><li><strong>Recursos da Comunidade</strong>: Os usuários podem participar da contribuição de conteúdo e discussões através do GitHub</li></ul><p>Reservamos o direito de modificar, suspender ou encerrar parte ou todos os serviços a qualquer momento, sem aviso prévio.</p><h2 id="_2-registro-e-gerenciamento-de-conta" tabindex="-1">2. Registro e Gerenciamento de Conta <a class="header-anchor" href="#_2-registro-e-gerenciamento-de-conta" aria-label="Permalink to &quot;2. Registro e Gerenciamento de Conta&quot;">​</a></h2><h3 id="condicoes-de-registro" tabindex="-1">Condições de Registro <a class="header-anchor" href="#condicoes-de-registro" aria-label="Permalink to &quot;Condições de Registro&quot;">​</a></h3><ul><li>Você deve ter pelo menos 16 anos de idade (ou ter atingido a maioridade em sua região)</li><li>Fornecer informações de registro verdadeiras e precisas</li><li>Cada usuário pode registrar apenas uma conta</li></ul><h3 id="seguranca-da-conta" tabindex="-1">Segurança da Conta <a class="header-anchor" href="#seguranca-da-conta" aria-label="Permalink to &quot;Segurança da Conta&quot;">​</a></h3><ul><li>Você é responsável por guardar suas credenciais de conta e não deve compartilhá-las com terceiros</li><li>Se descobrir que sua conta foi comprometida, entre em contato conosco imediatamente</li><li>Você assume total responsabilidade por perdas causadas por má gestão da conta</li></ul><h3 id="cancelamento-de-conta" tabindex="-1">Cancelamento de Conta <a class="header-anchor" href="#cancelamento-de-conta" aria-label="Permalink to &quot;Cancelamento de Conta&quot;">​</a></h3><p>Você pode solicitar o cancelamento da sua conta a qualquer momento. Após o cancelamento, seus dados pessoais serão excluídos em até 30 dias, mas o conteúdo publicado publicamente ainda pode ser mantido.</p><h2 id="_3-normas-de-comportamento-do-usuario" tabindex="-1">3. Normas de Comportamento do Usuário <a class="header-anchor" href="#_3-normas-de-comportamento-do-usuario" aria-label="Permalink to &quot;3. Normas de Comportamento do Usuário&quot;">​</a></h2><p>Ao usar esta plataforma, você concorda em não realizar os seguintes comportamentos:</p><ul><li>Publicar conteúdo ilegal, prejudicial, ameaçador, assediador, difamatório ou que viole direitos de terceiros</li><li>Fingir ser outra pessoa ou fornecer declarações falsas sobre sua identidade</li><li>Acessar não autorizadamente contas ou sistemas de terceiros</li><li>Interferir ou destruir o funcionamento normal do serviço</li><li>Usar ferramentas automatizadas para coletar conteúdo em larga escala (exceto uso razoável de API)</li><li>Usar o conteúdo do tutorial para fins comerciais sem cumprir o acordo de licença</li></ul><h2 id="_4-direitos-de-propriedade-intelectual" tabindex="-1">4. Direitos de Propriedade Intelectual <a class="header-anchor" href="#_4-direitos-de-propriedade-intelectual" aria-label="Permalink to &quot;4. Direitos de Propriedade Intelectual&quot;">​</a></h2><h3 id="nota-sobre-licenca-de-codigo-aberto" tabindex="-1">Nota sobre Licença de Código Aberto <a class="header-anchor" href="#nota-sobre-licenca-de-codigo-aberto" aria-label="Permalink to &quot;Nota sobre Licença de Código Aberto&quot;">​</a></h3><ul><li><strong>Conteúdo do Tutorial</strong>: Adotando o protocolo <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a>, permite compartilhamento e adaptação não comerciais, mas requer atribuição e compartilhamento da mesma forma</li><li><strong>Construção do Site</strong>: Este projeto é construído com base no <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>, seguindo o protocolo MIT</li><li><strong>Contribuições do Usuário</strong>: O conteúdo que você enviar é autorizado por padrão a ser usado pela plataforma sob a premissa de cumprir os protocolos acima</li></ul><p>As marcas registradas, logotipos e outras identidades de marca do OpenCodeDocs são protegidas por lei e não podem ser usadas sem autorização.</p><h2 id="_5-isencao-de-responsabilidade" tabindex="-1">5. Isenção de Responsabilidade <a class="header-anchor" href="#_5-isencao-de-responsabilidade" aria-label="Permalink to &quot;5. Isenção de Responsabilidade&quot;">​</a></h2><ul><li><strong>Interrupção do Serviço</strong>: Não garantimos que o serviço seja contínuo ou livre de erros. Não nos responsabilizamos por interrupções do serviço causadas por manutenção, upgrades ou força maior</li><li><strong>Precisão do Conteúdo</strong>: O conteúdo do tutorial é apenas para referência e não garantimos sua disponibilidade em todos os ambientes</li><li><strong>Risco de Uso de Código</strong>: Você assume seus próprios riscos ao executar o código do tutorial. Recomenda-se testar em ambiente isolado</li><li><strong>Links de Terceiros</strong>: Este site pode conter links para sites de terceiros e não somos responsáveis pelo conteúdo deles</li></ul><h2 id="_6-modificacao-do-acordo" tabindex="-1">6. Modificação do Acordo <a class="header-anchor" href="#_6-modificacao-do-acordo" aria-label="Permalink to &quot;6. Modificação do Acordo&quot;">​</a></h2><p>Podemos modificar este acordo periodicamente. O acordo modificado será publicado no site e você será notificado das seguintes formas:</p><ul><li>Anúncio em local proeminente no site</li><li>Envio de notificação por e-mail registrado (se aplicável)</li></ul><p>Continuar a usar nossos serviços significa que você aceita o acordo modificado. Se você discordar da modificação, pare de usar o serviço.</p><h2 id="_7-resolucao-de-disputas" tabindex="-1">7. Resolução de Disputas <a class="header-anchor" href="#_7-resolucao-de-disputas" aria-label="Permalink to &quot;7. Resolução de Disputas&quot;">​</a></h2><ul><li><strong>Lei Aplicável</strong>: Este acordo é regido pelas leis da República Popular da China</li><li><strong>Resolução de Disputas</strong>: Ambas as partes devem resolver disputas através de consultas amigáveis; se a consulta falhar, qualquer parte pode entrar com uma ação no tribunal popular competente no local do réu</li></ul><h2 id="_8-informacoes-de-contato" tabindex="-1">8. Informações de Contato <a class="header-anchor" href="#_8-informacoes-de-contato" aria-label="Permalink to &quot;8. Informações de Contato&quot;">​</a></h2><p>Se você tiver alguma dúvida sobre este acordo, entre em contato:</p><ul><li><strong>E-mail</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">vbgate/opencodedocs</a></li></ul>',32)])])}const g=o(i,[["render",t]]);export{p as __pageData,g as default};
